import { Resend } from 'resend';

export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method Not Allowed' });

  const { nom, email, telephone, type_projet, message } = JSON.parse(req.body);

  // Validation serveur
  if (!nom || !email || !message) return res.status(400).json({ error: 'Champs manquants' });

  const resend = new Resend(process.env.RESEND_API_KEY);

  await Promise.all([
    resend.emails.send({ from, to: process.env.EMAIL_PAYSAGISTE, subject, html }),
    resend.emails.send({ from, to: email, subject, html })
  ]);

  res.status(200).json({ success: true });
}
